<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Ubuntu Desktop Environment</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --taskbar-bg: #2d2d2d;
            --window-bg: #303030;
            --text-color: #e0e0e0;
            --accent-color: #e95420; /* Ubuntu orange-ish */
            --header-bg: #2c2c2c;
            --border-color: #444;
        }

        * { box-sizing: border-box; user-select: none; }

        body, html { margin: 0; padding: 0; height: 100%; width: 100%; overflow: hidden; font-family: 'Ubuntu', 'Segoe UI', sans-serif; background-color: var(--bg-color); color: var(--text-color); }

        /* Desktop Area */
        #desktop {
            width: 100vw;
            height: calc(100vh - 48px); /* Subtract taskbar height */
            position: relative;
            background: linear-gradient(135deg, #2b32b2 0%, #1488cc 100%); /* Ubuntu-ish blue gradient */
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: fixed;
            bottom: 0;
            left: 0;
            width: 100%;
            height: 48px;
            background-color: var(--taskbar-bg);
            display: flex;
            align-items: center;
            padding: 0 10px;
            box-shadow: 0 -2px 5px rgba(0,0,0,0.3);
            z-index: 1000;
        }

        .launcher {
            width: 48px;
            height: 48px;
            margin-right: 10px;
            border-radius: 8px;
            display: flex;
            justify-content: center;
            align-items: center;
            cursor: pointer;
            transition: background 0.2s;
            font-size: 24px;
        }

        .launcher:hover { background-color: #444; }

        /* Icons for launchers */
        #open-files::before { content: "📁"; }
        #open-notepad::before { content: "📝"; }

        /* Windows */
        .window {
            position: absolute;
            background-color: var(--window-bg);
            border-radius: 6px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: flex;
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
            overflow: hidden;
            border: 1px solid #000;
        }

        .window-header {
            height: 36px;
            background-color: var(--header-bg);
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 10px;
            cursor: move; /* Visual cue for dragging, though not strictly implemented in vanilla JS without complex logic */
        }

        .win-title { font-size: 14px; font-weight: bold; pointer-events: none;}

        .win-close {
            width: 20px;
            height: 20px;
            border-radius: 50%;
            background-color: #c0392b;
            color: white;
            display: flex;
            justify-content: center;
            align-items: center;
            cursor: pointer;
            font-size: 12px;
            line-height: 1;
        }
        .win-close:hover { background-color: #e74c3c; }

        /* Files App Specifics */
        #files-window { top: 50px; left: 50px; width: 600px; height: 400px; }

        #files-path-bar {
            background-color: #222;
            padding: 8px;
            font-family: monospace;
            color: #aaa;
            border-bottom: 1px solid var(--border-color);
            display: flex;
            align-items: center;
        }

        #files-up-btn {
            background: none;
            border: none;
            color: #888;
            cursor: pointer;
            margin-right: 10px;
            font-size: 16px;
        }
        #files-up-btn:hover { color: white; }

        #files-content {
            flex: 1;
            padding: 10px;
            overflow-y: auto;
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            grid-auto-rows: 90px;
            gap: 5px;
        }

        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            border-radius: 4px;
            padding: 5px;
            text-align: center;
            font-size: 12px;
        }

        .fs-item:hover { background-color: #444; }
        .fs-item.folder::before { content: "📁"; font-size: 24px; margin-bottom: 5px; }
        .fs-item.file::before { content: "📄"; font-size: 24px; margin-bottom: 5px; }

        /* Notepad App Specifics */
        #notepad-window { top: 60px; left: 60px; width: 500px; height: 350px; }

        #tabs-container {
            background-color: #2c2c2c;
            display: flex;
            align-items: center;
            padding-left: 5px;
            border-bottom: 1px solid var(--border-color);
            height: 30px;
        }

        .tab {
            background-color: #3a3a3a;
            color: #ccc;
            padding: 4px 12px;
            margin-right: 2px;
            border-radius: 4px 4px 0 0;
            font-size: 13px;
            cursor: pointer;
            max-width: 150px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .tab.active { background-color: var(--window-bg); color: white; border-bottom: 2px solid #e95420; }

        #new-tab-btn {
            margin-left: auto;
            background: none;
            border: none;
            color: #888;
            cursor: pointer;
            font-size: 16px;
            padding: 0 5px;
        }
        #new-tab-btn:hover { color: white; }

        #editor {
            flex: 1;
            background-color: var(--window-bg);
            color: #ddd;
            border: none;
            resize: none;
            padding: 10px;
            font-family: 'Ubuntu Mono', monospace;
            font-size: 14px;
            outline: none;
        }

        /* Scrollbar styling */
        ::-webkit-scrollbar { width: 8px; height: 8px; }
        ::-webkit-scrollbar-track { background: #222; }
        ::-webkit-scrollbar-thumb { background: #555; border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: #666; }

    </style>
</head>
<body>

<div id="desktop">

    <!-- Files Window -->
    <div id="files-window" class="window" style="display:none;">
        <div class="window-header">
            <span class="win-title">Files</span>
            <div class="win-close" onclick="toggleWindow('files-window')">✕</div>
        </div>
        <div id="files-path-bar">
            <button id="files-up-btn" title="Go Up">↑</button>
            <span id="files-path-text">/</span>
        </div>
        <div id="files-content">
            <!-- File items injected here -->
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window" style="display:none;">
        <div class="window-header">
            <span class="win-title">Notepad</span>
            <div class="win-close" onclick="toggleWindow('notepad-window')">✕</div>
        </div>
        <div id="tabs-container">
            <!-- Tabs injected here -->
        </div>
        <button id="new-tab-btn" title="New Tab">+</button>
        <textarea id="editor" placeholder="Type here..."></textarea>
    </div>

</div>

<div id="taskbar">
    <div id="open-files" class="launcher" onclick="toggleWindow('files-window')"></div>
    <div id="open-notepad" class="launcher" onclick="toggleWindow('notepad-window')"></div>
</div>

<script>
    // --- File System Data Structure ---
    const fileSystem = {
        name: "/",
        type: "dir",
        children: [
            { name: "bin", type: "dir", children: [] },
            { name: "etc", type: "dir", children: [] },
            { name: "home", type: "dir", children: [
                { name: "user", type: "dir", children: [
                    { name: "Documents", type: "dir", children: [
                        { name: "resume.txt", type: "file" },
                        { name: "notes.md", type: "file" }
                    ]},
                    { name: "Downloads", type: "dir", children: [
                        { name: "setup.exe", type: "file" },
                        { name: "image.png", type: "file" }
                    ]},
                    { name: "Pictures", type: "dir", children: [
                        { name: "vacation.jpg", type: "file" },
                        { name: "cat.gif", type: "file" }
                    ]}
                ]}
            ]},
            { name: "usr", type: "dir", children: [] },
            { name: "var", type: "dir", children: [] }
        ]
    };

    // --- State Management ---
    let currentPath = []; // Array of node objects representing the path stack
    let activeWindow = null;

    // --- Initialization ---
    window.onload = function() {
        initFileSystem();
        initNotepad();
    };

    // --- File System Logic ---

    function initFileSystem() {
        renderFiles();
    }

    function getCurrentNode() {
        if (currentPath.length === 0) return fileSystem;
        return currentPath[currentPath.length - 1];
    }

    function renderFiles() {
        const node = getCurrentNode();
        const container = document.getElementById('files-content');
        const pathText = document.getElementById('files-path-text');

        // Update Path Display
        let displayPath = "/";
        currentPath.forEach(p => {
            displayPath += "/" + p.name;
        });
        pathText.innerText = displayPath;

        // Clear and Re-render
        container.innerHTML = '';

        if (node.children) {
            node.children.forEach(item => {
                const el = document.createElement('div');
                el.className = `fs-item ${item.type}`;
                el.innerText = item.name;

                // Double click to enter folder
                if (item.type === 'dir') {
                    el.ondblclick = () => navigateTo(item);
                }

                container.appendChild(el);
            });
        } else {
            const emptyMsg = document.createElement('div');
            emptyMsg.style.gridColumn = "1 / -1";
            emptyMsg.style.display = "flex";
            emptyMsg.style.justifyContent = "center";
            emptyMsg.style.alignItems = "center";
            emptyMsg.innerText = "Empty Directory";
            container.appendChild(emptyMsg);
        }
    }

    function navigateTo(item) {
        currentPath.push(item);
        renderFiles();
    }

    // Handle Up Button
    document.getElementById('files-up-btn').addEventListener('click', () => {
        if (currentPath.length > 0) {
            currentPath.pop();
            renderFiles();
        }
    });

    // --- Notepad Logic ---

    const notepadState = {
        tabs: [], // Array of objects: { id, title, content }
        activeTabId: null
    };

    function initNotepad() {
        loadNotepadFromStorage();
        renderNotepadTabs();

        // Editor Input Listener
        const editor = document.getElementById('editor');
        editor.addEventListener('input', (e) => {
            const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeTabId);
            if (activeTab) {
                activeTab.content = e.target.value;
                saveNotepadToStorage();
            }
        });

        // New Tab Listener
        document.getElementById('new-tab-btn').addEventListener('click', createNewTab);
    }

    function loadNotepadFromStorage() {
        const saved = localStorage.getItem('ubuntu_notepad_data');
        if (saved) {
            notepadState.tabs = JSON.parse(saved);
            // Ensure we have an active tab, pick first one or default
            if (notepadState.tabs.length === 0) {
                createNewTab();
            } else {
                notepadState.activeTabId = notepadState.tabs[0].id;
            }
        } else {
            // Default state
            createNewTab();
        }
    }

    function saveNotepadToStorage() {
        localStorage.setItem('ubuntu_notepad_data', JSON.stringify(notepadState.tabs));
    }

    function renderNotepadTabs() {
        const container = document.getElementById('tabs-container');
        container.innerHTML = '';

        notepadState.tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = `tab ${tab.id === notepadState.activeTabId ? 'active' : ''}`;
            tabEl.innerText = tab.title;

            tabEl.onclick = () => switchTab(tab.id);
            container.appendChild(tabEl);
        });

        // Update editor content
        const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeTabId);
        if (activeTab) {
            document.getElementById('editor').value = activeTab.content;
        }
    }

    function createNewTab() {
        const id = 'tab-' + Date.now();
        const title = `Untitled-${notepadState.tabs.length + 1}`;

        notepadState.tabs.push({
            id: id,
            title: title,
            content: ""
        });

        // Make new tab active
        switchTab(id);
    }

    function switchTab(tabId) {
        notepadState.activeTabId = tabId;
        renderNotepadTabs();
    }

    // --- Window Management ---

    function toggleWindow(windowId) {
        const win = document.getElementById(windowId);

        if (win.style.display === 'none') {
            win.style.display = 'flex';
            // Bring to front logic could go here, simplified for this task
            activeWindow = windowId;
        } else {
            win.style.display = 'none';
        }
    }

</script>
</body>
</html>
